{"path": "/tmp/sv-cdeeb3aed77f40b7b2eb7b13fa030681/Components/Pages/Catalog/CatalogFilters.razor", "file_text": "<div class="p-3 border rounded bg-light">
    <h5>Filters</h5>

    <div class="mb-3">
        <label class="form-label fw-bold">Categories</label>
        @if (Categories is not null)
        {
            @foreach (var category in Categories)
            {
                <div class="form-check">
                    <input class="form-check-input" type="checkbox" id="@($"cat-{category}")"
                           checked="@selectedCategories.Contains(category)"
                           @onchange="@(e => ToggleCategory(category, (bool)e.Value!))" />
                    <label class="form-check-label" for="@($"cat-{category}")">@category</label>
                </div>
            }
        }
    </div>

    <div class="mb-3">
        <label class="form-label fw-bold">Price Range</label>
        <div class="d-flex gap-2">
            <input type="number" class="form-control form-control-sm" placeholder="Min"
                   @bind="minPrice" @bind:event="oninput" />
            <input type="number" class="form-control form-control-sm" placeholder="Max"
                   @bind="maxPrice" @bind:event="oninput" />
        </div>
    </div>

    <div class="mb-3 form-check">
        <input class="form-check-input" type="checkbox" id="inStockOnly" @bind="inStockOnly" />
        <label class="form-check-label" for="inStockOnly">In Stock Only</label>
    </div>

    <div class="d-grid gap-2">
        <button class="btn btn-primary btn-sm" @onclick="ApplyFilters">Apply Filters</button>
        <button class="btn btn-outline-secondary btn-sm" @onclick="ClearFilters">Clear Filters</button>
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public List<string>? Categories { get; set; }

    [Parameter]
    public EventCallback<ProductFilter> OnFiltersApplied { get; set; }

    [Parameter]
    public EventCallback OnFiltersCleared { get; set; }

    private HashSet<string> selectedCategories = new();
    private decimal? minPrice;
    private decimal? maxPrice;
    private bool inStockOnly;

    private void ToggleCategory(string category, bool isChecked)
    {
        if (isChecked)
            selectedCategories.Add(category);
        else
            selectedCategories.Remove(category);
    }

    private async Task ApplyFilters()
    {
        var filter = new ProductFilter(
            Categories: selectedCategories.Count > 0 ? selectedCategories.ToList() : null,
            MinPrice: minPrice,
            MaxPrice: maxPrice,
            InStockOnly: inStockOnly
        );
        await OnFiltersApplied.InvokeAsync(filter);
    }

    private async Task ClearFilters()
    {
        selectedCategories.Clear();
        minPrice = null;
        maxPrice = null;
        inStockOnly = false;
        await OnFiltersCleared.InvokeAsync();
    }
}
"}

{"path": "/tmp/sv-cdeeb3aed77f40b7b2eb7b13fa030681/Components/Pages/Catalog/CatalogToolbar.razor", "file_text": "<div class="d-flex justify-content-between align-items-center mb-3">
    <div>
        <select class="form-select form-select-sm" style="width: auto;" @onchange="HandleSortChange">
            <option value="price_asc" selected="@(CurrentSort == "price_asc")">Price: Low to High</option>
            <option value="price_desc" selected="@(CurrentSort == "price_desc")">Price: High to Low</option>
            <option value="name_asc" selected="@(CurrentSort == "name_asc")">Name: A-Z</option>
            <option value="rating_desc" selected="@(CurrentSort == "rating_desc")">Rating: Highest</option>
        </select>
    </div>
    <div class="text-muted small">
        @if (TotalCount > 0)
        {
            var start = (Page - 1) * PageSize + 1;
            var end = Math.Min(Page * PageSize, TotalCount);
            <span>Showing @start–@end of @TotalCount products</span>
        }
    </div>
</div>

@code {
    [Parameter]
    public string CurrentSort { get; set; } = "price_asc";

    [Parameter]
    public int TotalCount { get; set; }

    [Parameter]
    public int Page { get; set; }

    [Parameter]
    public int PageSize { get; set; }

    [Parameter]
    public EventCallback<string> OnSortChanged { get; set; }

    private async Task HandleSortChange(ChangeEventArgs e)
    {
        await OnSortChanged.InvokeAsync(e.Value?.ToString());
    }
