@page "/catalog"
@rendermode InteractiveServer
@inject IProductService ProductService

<PageTitle>Product Catalog</PageTitle>

<h3 class="mb-4">Product Catalog</h3>

@if (errorMessage is not null)
{
    <div class="alert alert-danger">
        <strong>Error:</strong> @errorMessage
        <button class="btn btn-link" @onclick="RetryLoad">Retry</button>
    </div>
}
else
{
    <div class="row">
        <div class="col-md-3">
            <CatalogFilters Categories="categories"
                            OnFiltersApplied="HandleFiltersApplied"
                            OnFiltersCleared="HandleFiltersCleared" />
        </div>
        <div class="col-md-9">
            @if (isLoading)
            {
                <div class="d-flex justify-content-center py-5">
                    <div class="spinner-border text-primary" role="status">
                        <span class="visually-hidden">Loading...</span>
                    </div>
                </div>
            }
            else if (result is not null)
            {
                <CatalogToolbar CurrentSort="@sortBy"
                                TotalCount="result.TotalCount"
                                Page="currentPage"
                                PageSize="pageSize"
                                OnSortChanged="HandleSortChanged" />

                <ProductGrid Products="result.Items"
                             OnProductSelected="HandleProductSelected"
                             OnAddToCart="HandleAddToCart" />

                <CatalogPagination CurrentPage="currentPage"
                                   TotalPages="TotalPages"
                                   OnPageChanged="HandlePageChanged" />
            }
        </div>
    </div>
}

@code {
    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    private List<string>? categories;
    private PagedResult<Product>? result;
    private ProductFilter currentFilter = new(null, null, null, false);
    private string sortBy = "price_asc";
    private int currentPage = 1;
    private int pageSize = 12;
    private bool isLoading = true;
    private string? errorMessage;

    private int TotalPages => result is null || result.TotalCount == 0
        ? 1
        : (int)Math.Ceiling((double)result.TotalCount / pageSize);

    protected override async Task OnInitializedAsync()
    {
        await LoadData();
    }

    private async Task LoadData()
    {
        try
        {
            isLoading = true;
            errorMessage = null;

            var categoriesTask = ProductService.GetCategoriesAsync();
            var productsTask = ProductService.SearchAsync(currentFilter, sortBy, currentPage, pageSize);

            await Task.WhenAll(categoriesTask, productsTask);

            categories = await categoriesTask;
            result = await productsTask;
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            isLoading = false;
        }
    }

    private async Task SearchProducts()
    {
        try
        {
            isLoading = true;
            errorMessage = null;
            result = await ProductService.SearchAsync(currentFilter, sortBy, currentPage, pageSize);
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            isLoading = false;
        }
    }

    private async Task HandleFiltersApplied(ProductFilter filter)
    {
        currentFilter = filter;
        currentPage = 1;
        await SearchProducts();
    }

    private async Task HandleFiltersCleared()
    {
        currentFilter = new ProductFilter(null, null, null, false);
        currentPage = 1;
        await SearchProducts();
    }

    private async Task HandleSortChanged(string? newSort)
    {
        sortBy = newSort ?? "price_asc";
        currentPage = 1;
        await SearchProducts();
    }

    private async Task HandlePageChanged(int page)
    {
        currentPage = page;
        await SearchProducts();
    }

    private async Task HandleProductSelected(Product product)
    {
        await OnProductSelected.InvokeAsync(product);
    }

    private Task HandleAddToCart(Product product)
    {
        // Placeholder for cart functionality
        return Task.CompletedTask;
    }

    private async Task RetryLoad()
    {
        await LoadData();
    }
}

